UPDATE media_asset
SET alt_text = #{altText}
WHERE id = #{id} AND deleted_at IS NULL

UPDATE media_asset
SET status = 'DELETE_FAILED',
    next_delete_retry_at = #{nextRetryAt},
    last_delete_error = #{error}
WHERE id = #{id}
  AND status = 'DELETING'
